select 
from t_r_workflow_definition
where workspace_id = #{workspaceId}
  and project_code = #{projectCode}
  and code = #{code}
limit 1

select from t_r_workflow_definition where project_code = #{projectCode}
and name like concat('%', #{searchVal}, '%')
order by updated_at desc

select id
from t_r_workflow_definition
where workspace_id = #{workspaceId}

select count(*)
from t_r_workflow_definition
where project_code = #{projectCode}
  and name = #{name}
